/**
 * S3 Service Types and Interfaces
 * 
 * Defines the minimal, type-safe interface for S3 operations.
 * Tradeoffs considered:
 * - Stream vs Buffer: This service uses Buffers for simplicity at the cost of memory.
 *   For large file streaming, use the streaming methods.
 * - AwsCredentialIdentity vs simple object: Using AwsCredentialIdentity for SDK compatibility,
 *   but we provide helper functions to construct it.
 * - Tombstone markers: Using key prefix pattern (.tombstone/...) to avoid:
 *   a) Listing deleted objects in normal operations
 *   b) Lifecycle rules affecting metadata-only tombstones
 *   c) Race conditions with deleted content
 */

// Re-export AWS SDK types we depend on
export type { AwsCredentialIdentity } from '@aws-sdk/types';

/**
 * S3 Service Configuration
 * 
 * Design choice: Allow endpoint override for local testing (MinIO, LocalStack)
 * while maintaining production-ready defaults.
 */
export interface S3Config {
  /** AWS region */
  region: string;
  /** Bucket name */
  bucket: string;
  /** Optional: endpoint URL for S3-compatible services (e.g., MinIO, LocalStack) */
  endpoint?: string;
}

/**
 * S3 Operation Options
 * Common options across operations
 */
export interface S3OperationOptions {
  /** Optional abort signal for cancellation */
  abortSignal?: AbortSignal;
}

/**
 * Get Object Request
 */
export interface GetObjectRequest extends S3OperationOptions {
  /** Object key */
  key: string;
  /** Optional: specific version ID */
  versionId?: string;
}

/**
 * Get Object Result
 * 
 * Design choice: Return a simple buffer interface instead of streams
 * for ease of use in most bootstrap operations.
 * Use streaming methods for large files.
 */
export interface GetObjectResult {
  /** Object content as Buffer */
  body: Buffer;
  /** Content-Type header */
  contentType?: string;
  /** Content length in bytes */
  contentLength: number;
  /** Last modified timestamp */
  lastModified: Date;
  /** ETag (MD5 hash) */
  etag: string;
  /** Metadata attached to object */
  metadata: Record<string, string>;
  /** Version ID if bucket has versioning enabled */
  versionId?: string;
}

/**
 * Put Object Request
 */
export interface PutObjectRequest extends S3OperationOptions {
  /** Object key */
  key: string;
  /** Object content */
  body: Buffer | string;
  /** Optional: Content-Type (default: application/octet-stream) */
  contentType?: string;
  /** Optional: Additional metadata */
  metadata?: Record<string, string>;
  /** Optional: Storage class (default: STANDARD) */
  storageClass?: 'STANDARD' | 'REDUCED_REDUNDANCY' | 'GLACIER' | 'DEEP_ARCHIVE' | 'STANDARD_IA';
}

/**
 * Put Object Result
 */
export interface PutObjectResult {
  /** ETag of uploaded object */
  etag: string;
  /** Version ID if bucket has versioning enabled */
  versionId?: string;
}

/**
 * Delete Object Request
 */
export interface DeleteObjectRequest extends S3OperationOptions {
  /** Object key to delete */
  key: string;
  /** Optional: specific version ID (for versioned buckets) */
  versionId?: string;
}

/**
 * Delete Object Result
 */
export interface DeleteObjectResult {
  /** Whether deletion succeeded */
  success: boolean;
  /** Version ID of deleted marker (if versioned) */
  deleteMarkerVersionId?: string;
}

/**
 * List Objects Request
 * 
 * Design choice: Simplified pagination using continuation token pattern
 * following AWS SDK v3 conventions.
 */
export interface ListObjectsRequest extends S3OperationOptions {
  /** Prefix to filter objects (e.g., "uploads/2024/") */
  prefix?: string;
  /** Maximum keys to return (default: 1000) */
  maxKeys?: number;
  /** Continuation token for pagination */
  continuationToken?: string;
  /** Delimiter for folder-like listing (default: /) */
  delimiter?: string;
  /** Include objects in tombstone state */
  includeDeleted?: boolean;
}

/**
 * S3 Object representation
 */
export interface S3Object {
  /** Object key */
  key: string;
  /** Last modified timestamp */
  lastModified: Date;
  /** ETag */
  etag: string;
  /** Size in bytes */
  size: number;
  /** Storage class */
  storageClass: string;
  /** Is this object in a tombstone (soft-deleted) state */
  isDeleted?: boolean;
}

/**
 * Common prefix (folder) in list results
 */
export interface S3CommonPrefix {
  /** Prefix value */
  prefix: string;
}

/**
 * List Objects Result
 */
export interface ListObjectsResult {
  /** Objects in this page */
  objects: S3Object[];
  /** Common prefixes (folders) */
  commonPrefixes: S3CommonPrefix[];
  /** Total count of objects (may be truncated) */
  keyCount: number;
  /** Number of objects in this response */
  maxKeys: number;
  /** Whether results are truncated */
  isTruncated: boolean;
  /** Token for next page if truncated */
  nextContinuationToken?: string;
}

/**
 * Head Object Request
 */
export interface HeadObjectRequest extends S3OperationOptions {
  /** Object key */
  key: string;
  /** Optional: version ID */
  versionId?: string;
}

/**
 * Head Object Result (metadata only)
 */
export interface HeadObjectResult {
  /** Content-Type */
  contentType?: string;
  /** Content length in bytes */
  contentLength: number;
  /** Last modified timestamp */
  lastModified: Date;
  /** ETag */
  etag: string;
  /** Metadata attached to object */
  metadata: Record<string, string>;
  /** Version ID if bucket has versioning enabled */
  versionId?: string;
}

// ====================
// Tombstone Support
// ====================

/** Tombstone marker prefix - design choice explained in docstring above */
export const TOMBSTONE_PREFIX = '.tombstone/';

/**
 * Tombstone metadata stored with soft-deleted objects
 */
export interface TombstoneMetadata {
  /** Original key before deletion */
  originalKey: string;
  /** Deletion timestamp */
  deletedAt: Date;
  /** Original deletion reason */
  reason?: string;
  /** Original content metadata (cached for restore) */
  originalMetadata?: Record<string, string>;
  /** Original content size */
  originalSize?: number;
  /** Original content type */
  originalContentType?: string;
}

/**
 * Soft delete request
 */
export interface SoftDeleteRequest extends S3OperationOptions {
  /** Object key to soft-delete */
  key: string;
  /** Optional: reason for deletion (audit trail) */
  reason?: string;
}

/**
 * Soft delete result
 */
export interface SoftDeleteResult {
  /** Whether soft-delete succeeded */
  success: boolean;
  /** Tombstone key where metadata is stored */
  tombstoneKey: string;
  /** Timestamp of deletion */
  deletedAt: Date;
}

/**
 * Restore request
 */
export interface RestoreRequest extends S3OperationOptions {
  /** Object key to restore */
  key: string;
  /** Optional: restore to different key */
  targetKey?: string;
}

/**
 * Restore result
 */
export interface RestoreResult {
  /** Whether restore succeeded */
  success: boolean;
  /** Restored key */
  restoredKey: string;
  /** Timestamp of restore */
  restoredAt: Date;
}

/**
 * List tombstones request
 */
export interface ListTombstonesRequest extends S3OperationOptions {
  /** Filter by original key prefix */
  prefix?: string;
  /** Maximum results (default: 1000) */
  maxKeys?: number;
  /** Continuation token for pagination */
  continuationToken?: string;
}

/**
 * Tombstone entry
 */
export interface TombstoneEntry {
  /** Tombstone key */
  tombstoneKey: string;
  /** Original key */
  originalKey: string;
  /** Deletion timestamp */
  deletedAt: Date;
  /** Deletion reason */
  reason?: string;
  /** Size of original content */
  originalSize?: number;
}

/**
 * List tombstones result
 */
export interface ListTombstonesResult {
  /** Tombstone entries */
  tombstones: TombstoneEntry[];
  /** Pagination token */
  nextContinuationToken?: string;
}

// ====================
// Presigned URLs
// ====================

/**
 * Presigned URL operation type
 */
export type PresignedOperation = 'getObject' | 'putObject';

/**
 * Presigned URL request
 */
export interface GetPresignedUrlRequest {
  /** Operation type */
  operation: PresignedOperation;
  /** Object key */
  key: string;
  /** Optional: expiration time in seconds (default: 3600 = 1 hour, max: 604800 = 7 days) */
  expiresIn?: number;
  /** Optional: content type for putObject (recommended for PUT operations) */
  contentType?: string;
}

/**
 * Presigned URL result
 */
export interface GetPresignedUrlResult {
  /** Presigned URL */
  url: string;
  /** Expiration time in seconds */
  expiresIn: number;
  /** Expiration timestamp */
  expiresAt: Date;
}

// ====================
// Multipart Upload
// ====================

/**
 * Multipart upload initiation request
 */
export interface CreateMultipartUploadRequest extends S3OperationOptions {
  /** Object key */
  key: string;
  /** Optional: Content-Type */
  contentType?: string;
  /** Optional: metadata */
  metadata?: Record<string, string>;
  /** Optional: storage class */
  storageClass?: 'STANDARD' | 'REDUCED_REDUNDANCY' | 'GLACIER' | 'DEEP_ARCHIVE' | 'STANDARD_IA';
}

/**
 * Create multipart upload result
 */
export interface CreateMultipartUploadResult {
  /** Upload ID for subsequent parts */
  uploadId: string;
  /** Object key */
  key: string;
}

/**
 * Upload part request
 */
export interface UploadPartRequest extends S3OperationOptions {
  /** Object key */
  key: string;
  /** Upload ID from createMultipartUpload */
  uploadId: string;
  /** Part number (1-10000) */
  partNumber: number;
  /** Part content */
  body: Buffer;
}

/**
 * Part upload result
 */
export interface UploadPartResult {
  /** ETag for this part */
  etag: string;
  /** Part number */
  partNumber: number;
}

/**
 * Complete multipart upload request
 */
export interface CompleteMultipartUploadRequest extends S3OperationOptions {
  /** Object key */
  key: string;
  /** Upload ID */
  uploadId: string;
  /** List of completed parts (must be sorted by partNumber) */
  parts: { partNumber: number; etag: string }[];
}

/**
 * Complete multipart upload result
 */
export interface CompleteMultipartUploadResult {
  /** Location URL of the completed upload */
  location?: string;
  /** ETag */
  etag: string;
  /** Version ID if versioned */
  versionId?: string;
}

/**
 * Abort multipart upload request
 */
export interface AbortMultipartUploadRequest extends S3OperationOptions {
  /** Object key */
  key: string;
  /** Upload ID */
  uploadId: string;
}

// ====================
// S3 Service Interface
// ====================

/**
 * Minimal S3 Service Interface
 * 
 * Design philosophy: Async/await throughout, explicit error types,
 * no hidden side effects. All methods signal cancellation via AbortSignal.
 */
export interface IS3Service {
  // Core CRUD operations
  getObject(request: GetObjectRequest): Promise<GetObjectResult>;
  putObject(request: PutObjectRequest): Promise<PutObjectResult>;
  deleteObject(request: DeleteObjectRequest): Promise<DeleteObjectResult>;
  listObjects(request: ListObjectsRequest): Promise<ListObjectsResult>;
  headObject(request: HeadObjectRequest): Promise<HeadObjectResult | null>;
  objectExists(key: string): Promise<boolean>;

  // Tombstone (soft delete) operations
  softDelete(request: SoftDeleteRequest): Promise<SoftDeleteResult>;
  restore(request: RestoreRequest): Promise<RestoreResult>;
  listTombstones(request: ListTombstonesRequest): Promise<ListTombstonesResult>;
  purgeTombstone(key: string): Promise<boolean>;

  // Presigned URLs
  getPresignedUrl(request: GetPresignedUrlRequest): Promise<GetPresignedUrlResult>;

  // Multipart uploads
  createMultipartUpload(request: CreateMultipartUploadRequest): Promise<CreateMultipartUploadResult>;
  uploadPart(request: UploadPartRequest): Promise<UploadPartResult>;
  completeMultipartUpload(request: CompleteMultipartUploadRequest): Promise<CompleteMultipartUploadResult>;
  abortMultipartUpload(request: AbortMultipartUploadRequest): Promise<void>;

  // Lifecycle
  /** Clean up resources */
  destroy(): Promise<void>;
}

// ====================
// Error Types
